//! The closed worlds of the IDApTIK level object graph, and the verb registry.
//!
//! Closed worlds are what make generation decidable (ADR-0001): the relational
//! engine enumerates over these when an edit leaves a field fresh.

use crate::microkanren::{Goal, Term, membero};

/// One verb's contract: its ordered arguments, which are required, and the
/// finite domain of each argument that ranges over a closed world.
///
/// `args` is ordered because JSON key order is wire-significant and because
/// `solve()` binds its positional arguments in exactly this order.
#[derive(Clone, Copy, Debug)]
pub struct VerbSpec {
    pub name: &'static str,
    pub doc: &'static str,
    /// The state collection this verb appends to, or the field it sets.
    pub collection: &'static str,
    pub args: &'static [&'static str],
    pub required: &'static [&'static str],
    pub domains: &'static [(&'static str, &'static [&'static str])],
}

impl VerbSpec {
    /// The finite domain of `arg`, or `None` when the caller must supply it
    /// (ids and geometry are the proposer's job, not the kernel's).
    pub fn domain(&self, arg: &str) -> Option<&'static [&'static str]> {
        self.domains
            .iter()
            .find(|(a, _)| *a == arg)
            .map(|(_, d)| *d)
    }
}

