/// Goal: `t` is a member of `domain`. The `membero`-style domain relation
/// that makes an out-of-vocabulary value ungeneratable rather than merely
/// detectable.
pub fn in_domain(t: Term, domain: &[&str]) -> Goal {
    let items: Vec<Term> = domain.iter().map(|s| Term::str(*s)).collect();
    membero(t, &items)
}
